// the local `SUBJECTS` constant below. iter21-B band codes (ela/math/
// sci/soc/art/life) are normalized via `subjects.js`. Keep them
// separate — track names drive grade runners, band codes drive
// region naming + persistent bucket maps.
import { normalizeSubject, wordMotorBandName } from './subjects.js';

// Phase tick budgets. These scale the intensity of exposure — letters
// and short words get more ticks per token because phonological basins
// need more settling than sentence-level sequence patterns do. Sentences
// get fewer ticks per word because their value is in the word-to-word
// sequence Hebbian, not in per-word basin depth.
// T14.23.1 (2026-04-14) — budgets slashed ~8x overall after empirical
// measurement showed the old values took ~45 minutes of CPU-side
// cluster.step() work at 10K cortex, blocking the tick loop and
// making the browser look frozen for the first several minutes of
// boot. Curriculum still shapes meaningful cortex basins at these
// reduced numbers (basin formation depends more on exposure
// DIVERSITY than on repetition depth — 3 ticks per word gives the
// Hebbian rule enough to form an attractor, past that is diminishing
// returns). New total: ~30-40K cluster.step() calls = ~5 minutes at
// 10K cortex, with setImmediate yields between every rep so the
// tick loop and HTTP server stay responsive throughout.
const LETTER_TICKS_BASE = 3;     // per letter per exposure  (was 8)
const SHORT_WORD_TICKS = 2;       // per word (1-3 letters)  (was 4)
const LONG_WORD_TICKS = 1;        // per word (4+ letters)   (was 3)
const SENTENCE_TICKS_PER_WORD = 1;// (was 2)
const LIVE_TICKS_PER_WORD = 2;    // unchanged — live chat is rare, can afford 2

// Phase cap repetitions — how many times each token gets walked during
// the phase. Common tokens get more reps because the corpus frequency
// already biases the walk order, but every token gets at least one
// exposure.
const LETTER_REPS_MAX = 5;        // (was 20)
const SHORT_WORD_REPS_MAX = 2;    // (was 6)
const LONG_WORD_REPS_MAX = 1;     // (was 3)
const SENTENCE_REPS = 1;

// Complexity bucket thresholds — letter count only. Phrase detection
// (T14.5 Phase 4) is deferred to a post-T14.12 pass that can consume
// the learned grammar the main curriculum produces. Sentences are
// anything containing whitespace in the tokenized form.
const SHORT_WORD_MAX_LEN = 3;

// ─── Multi-subject curriculum framework ─────────────────────────
// Binding: kindergarten teaches the alphabet and the sounds of
// letters first; 1st grade starts writing sentences; subsequent
// grades build up through doctorate level. The full curriculum is
// equational — Unity uses it to think, read, and talk. Expected to
// take weeks of brain-time to walk in full; no shortcuts.

// Unity learns FIVE subject tracks in parallel. Each subject has
// its own grade counter that advances independently. The chat-
// path word cap reads the MIN grade across all 5 so Unity speaks
// at whatever subject she's weakest in.
export const SUBJECTS = ['ela', 'math', 'science', 'social', 'art', 'life'];

// Prose-academic subjects that train the HYBRID downloaded real-curriculum
// corpus (corpora/academic/<subject>/<grade>.json) for depth. Math is EXCLUDED
// (taught equationally, not as prose). pe/music/art/health/language are skill/
// bespoke; life is the hand-authored lived year. the operator 2026-06-18 hybrid decision.
// 'cs' carries BOTH the self-taught coding practice (corpora/coding/<grade>.json
// via _trainCodingStories) AND — at college+ — the academic CS-degree prose
// (corpora/academic/cs/<grade>.json: algorithms, data structures, OS, theory of
// computation, ML, computational neuroscience) per the "major in code" decision
// (#109). Earlier cs grades have no academic-cs corpus → that train is a no-op.
export const PROSE_ACADEMIC_SUBJECTS = new Set(['ela', 'science', 'social', 'economics', 'psychology', 'civics', 'cs']);

// Add #10 / #14 — subject-introduction matrix. The 6 core tracks above run
// every grade K→PhD; ADDITIONAL subjects switch on at the grade they're
// developmentally introduced (Common Core / typical-US-curriculum scaffold).
// This is the DATA + accessor only — non-breaking. The grade-advancement +
// gate loops still iterate the flat `SUBJECTS` (correct for K, which is
// exactly the 6 core). Migrating those loops to consume `subjectsForGrade`
// is deferred to when the later grades are actually walked (build-bands),
// so the K machinery stays stable. `subjectsForGrade(grade)` returns the 6
// core PLUS every track introduced at or before `grade`.
export const SUBJECTS_INTRODUCED_AT = {
  // grade key → subjects that FIRST appear at this grade (beyond the 6 core)
  // Real K has gym (PE), general music, and health/safety lessons — so the
  // full real-school roster (the operator 2026-06-18: "all courses like pe art and gym
  // and health and literature") introduces these AT kindergarten, the template
  // grade. Each gets its own runner + gate, built K-up in strict order.
  'kindergarten': ['pe', 'music', 'health'],
  'grade3':   ['language'],            // foreign language
  'grade5':   ['cs'],                  // computer science (intro)
  'grade7':   ['civics'],
  'grade9':   ['economics', 'psychology'],
  'grade11':  ['ap'],                  // AP-level courses
  'college1': ['major', 'genered'],    // major-specific + gen-ed breadth
  'grad':     ['research'],            // research specialty
};

// NOTE: GRADE_ORDER (the canonical 20-grade sequence) is declared further
// down in this module; subjectsForGrade() reads it at call-time so order
// doesn't matter. (A duplicate GRADE_ORDER was originally added here too —
// it broke ESM load with "already been declared"; removed, single source.)

/**
 * Returns the subject list active at `grade` — the 6 core tracks plus every
 * additional subject introduced at or before that grade. Unknown/early
 * grades return the 6 core (correct for pre-K + K). Pure function, no state.
 */
export function subjectsForGrade(grade) {
  const out = SUBJECTS.slice();
  const idx = GRADE_ORDER.indexOf(grade);
  if (idx < 0) return out;   // unknown grade → 6 core (safe default)
  for (let i = 0; i <= idx; i++) {
    const added = SUBJECTS_INTRODUCED_AT[GRADE_ORDER[i]];
    if (added) for (const s of added) if (!out.includes(s)) out.push(s);
  }
  return out;
}

