    this._hb(`[Curriculum] _probeRL2CharacterIdentification — ${passed}/${TRIALS} (${(score * 100).toFixed(0)}%) ≥ ${(THRESHOLD * 100).toFixed(0)}%? ${thresholdHit ? '✓' : '✗'}`);
    this._recordFullMindKResult('RL-2', { score, thresholdHit, evidence });
